import{_ as s,c as a,o as i,b as d}from"./app.aaa68922.js";const h='{"title":"\u0413\u043B\u0430\u0432\u0430 10","description":"","frontmatter":{"title":"\u0413\u043B\u0430\u0432\u0430 10","subtitle":"\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0430","tags":"malini","date":"2020-09-01T00:00:00.000Z"},"headers":[],"relativePath":"texts/malini-vijayottara/10.md"}',c={},n=d('<div class="stanza"><a href="#s10.1" id="s10.1" class="num">10.1</a><p>\u0422\u0435\u043F\u0435\u0440\u044C (\u043F\u043E\u0432\u0435\u0434\u0430\u044E) \u043E \u043B\u0430\u043A\u0445\u0430\u0445 (\u0441\u0442\u0430 \u0442\u044B\u0441\u044F\u0447\u0430\u0445 \u0434\u0436\u0430\u043F), \u043D\u0430\u0434\u0435\u043B\u044F\u044E\u0449\u0438\u0445 \u0443\u0441\u043F\u0435\u0445\u043E\u043C \u0432 \u0441\u0430\u0434\u0445\u0430\u043D\u0435. (\u0421\u0430\u0434\u0445\u0430\u043A\u0430 \u0434\u043E\u043B\u0436\u0435\u043D \u043E\u0431\u043B\u0430\u0434\u0430\u0442\u044C) \u0437\u043D\u0430\u043D\u0438\u0435\u043C \u0448\u0430\u0441\u0442\u0440, \u0443\u0440\u0430\u0432\u043D\u043E\u0432\u0435\u0448\u0435\u043D\u043D\u043E\u0441\u0442\u044C\u044E, \u043C\u0443\u0434\u0440\u043E\u0441\u0442\u044C\u044E, \u043D\u0435\u0443\u044F\u0437\u0432\u0438\u043C\u043E\u0441\u0442\u044C\u044E, \u043F\u0440\u0430\u0432\u0434\u0438\u0432\u043E\u0441\u0442\u044C\u044E, \u0441\u0442\u043E\u0439\u043A\u043E\u0441\u0442\u044C\u044E .</p></div><div class="stanza"><a href="#s10.2" id="s10.2" class="num">10.2</a><p>\u0418\u0441\u043F\u044B\u0442\u0430\u0432 \u0441\u0430\u0434\u0445\u0430\u043A\u0443 (\u043D\u0430 \u044D\u0442\u0438 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430) \u0433\u0443\u0440\u0443 \u0434\u043E\u043B\u0436\u0435\u043D \u0443\u043A\u0440\u0435\u043F\u0438\u0442\u044C (\u0438\u0445). \u0421\u043E\u0432\u0435\u0440\u0448\u0438\u0432 \u043A\u0430\u043A \u043F\u043E\u0434\u043E\u0431\u0430\u0435\u0442 \u043F\u043E\u0447\u0438\u0442\u0430\u043D\u0438\u0435 \u041F\u0430\u0440\u0430\u043C\u0435\u0448\u0432\u0430\u0440\u044B \u043A\u0430\u043A \u0438 \u0440\u0430\u043D\u044C\u0448\u0435;</p></div><div class="stanza"><a href="#s10.3" id="s10.3" class="num">10.3</a><p>\u0412\u0442\u043E\u0440\u044B\u043C (\u0434\u0435\u043B\u043E\u043C \u043E\u043D \u0434\u043E\u043B\u0436\u0435\u043D \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u044C), \u043A\u0430\u043A \u0438 \u0440\u0430\u043D\u0435\u0435, \u0441\u043E\u0441\u0443\u0434, \u0441\u0434\u0435\u043B\u0430\u043D\u043D\u044B\u0439 \u0438\u0437 \u0437\u043E\u043B\u043E\u0442\u0430 \u0438 \u043F\u0440\u043E\u0447\u0435\u0433\u043E, \u0431\u0435\u0437 \u043F\u043E\u0432\u0440\u0435\u0436\u0434\u0435\u043D\u0438\u0439. \u0412\u043E \u0432\u0441\u0435\u043C (\u043B\u043E\u0442\u043E\u0441\u0435) \u0432 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435 \u043B\u043E\u0442\u043E\u0441\u0430, \u0438\u043B\u0438 \u0432 \u044E\u0436\u043D\u043E\u043C \u043B\u0435\u043F\u0435\u0441\u0442\u043A\u0435,</p></div><div class="stanza"><a href="#s10.4" id="s10.4" class="num">10.4</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0447\u0438\u0442\u0430\u0442\u044C \u041D\u0430\u044F\u043A\u043E\u0432, \u0441 \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u043E\u0439 \u043C\u0430\u043D\u0442\u0440\u043E\u0439 \u0446\u0432\u0435\u0442\u0430\u043C\u0438 \u0438 \u043F\u0440\u043E\u0447\u0438\u043C. \u0412\u044B\u043F\u043E\u043B\u043D\u0438\u0432 \u0442\u044F\u0441\u044F\u0447\u0435\u043A\u0440\u0430\u0442\u043D\u0443\u044E \u0442\u0430\u0440\u043F\u0430\u043D\u0443, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0432\u0435\u0440\u0448\u0438\u0442\u044C \u0430\u0431\u0445\u0438\u0448\u0435\u043A\u0443 .</p></div><div class="stanza"><a href="#s10.5" id="s10.5" class="num">10.5</a><p>\u0412 \u0431\u043B\u0430\u0433\u043E\u043F\u0440\u0438\u044F\u0442\u043D\u043E\u0439 \u0431\u0445\u0430\u0434\u0440\u0430 \u043F\u0438\u0442\u0445\u0435, \u0443 \u043F\u043E\u0447\u0438\u0442\u0430\u0435\u043C\u043E\u0433\u043E \u0434\u0435\u0440\u0435\u0432\u0430 \u0448\u0440\u0438\u043F\u0430\u0440\u043D\u0430, \u043F\u043E\u043C\u0435\u0441\u0442\u0438\u0432 (\u0443\u0447\u0435\u043D\u0438\u043A\u0430?) \u043B\u0438\u0446\u043E\u043C \u043D\u0430 \u0432\u043E\u0441\u0442\u043E\u043A \u0438\u043B\u0438 \u043D\u0430 \u0441\u0435\u0432\u0435\u0440, \u043E\u043C\u044B\u0442\u043E\u0433\u043E, \u0443\u043A\u0440\u0430\u0448\u0435\u043D\u043D\u043E\u0433\u043E \u0446\u0432\u0435\u0442\u0430\u043C\u0438 \u0438 \u043F\u0440\u043E\u0447\u0438\u043C,</p></div><div class="stanza"><a href="#s10.6" id="s10.6" class="num">10.6</a><p>\u0421\u043E\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u043E\u0435 \u0442\u0435\u043B\u043E \u043C\u0430\u043D\u0442\u0440\u044B, \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0438\u0442 \u0431\u043B\u0430\u0433\u043E\u043F\u0440\u0438\u0442\u043D\u044B\u0435 (\u043F\u0440\u0438\u0437\u043D\u0430\u043A\u0438). \u0417\u0432\u0443\u043A\u0438 \u0440\u0430\u043A\u043E\u0432\u0438\u043D\u044B \u0431\u0430\u0440\u0430\u0431\u0430\u043D\u0430, \u0438 \u043F\u0440\u043E\u0447\u0435\u0433\u043E, - \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B \u043A\u0430\u043A \u0431\u043B\u0430\u0433\u043E\u043F\u0440\u0438\u044F\u0442\u043D\u044B\u0435 \u0437\u0432\u0443\u0447\u0430\u0449\u0438\u0435 \u043F\u0440\u0438\u0437\u043D\u0430\u043A\u0438 .</p></div><div class="stanza"><a href="#s10.7" id="s10.7" class="num">10.7</a><p>\u0421 \u0432\u0441\u0435\u043C\u0438 \u0446\u0430\u0440\u0441\u043A\u0438\u043C\u0438 \u0443\u043F\u0430\u0447\u0430\u0440\u0430\u043C\u0438 \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0432 \u043D\u0430\u0434 \u043D\u0438\u043C \u0430\u0431\u0445\u0438\u0448\u0435\u043A\u0443, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0435\u0433\u043E \u0440\u0430\u0432\u043D\u044B\u043C \u0421\u0430\u0434\u0430\u0448\u0438\u0432\u0435, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0435\u0433\u043E \u0443\u043A\u0440\u0430\u0441\u0438\u0442\u044C .</p></div><div class="stanza"><a href="#s10.8" id="s10.8" class="num">10.8</a><p>\u041F\u043E\u0447\u0442\u0438\u0432 \u0432\u043D\u043E\u0432\u044C \u0412\u043B\u0430\u0434\u044B\u043A\u0443 \u0431\u043E\u0433\u043E\u0432, \u043F\u0443\u0441\u0442\u044C \u043C\u0443\u0434\u0440\u044B\u0439 \u0434\u0430\u0441\u0442 \u0435\u043C\u0443 \u043C\u0430\u043D\u0442\u0440\u0443. \u041F\u0443\u0441\u0442\u044C \u043F\u043E\u043C\u0435\u0441\u0442\u0438\u0442 (\u0432 \u0435\u0433\u043E \u0442\u0435\u043B\u043E \u0418\u0448\u0432\u0430\u0440\u0443, \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u044F \u0430\u0431\u0445\u0438\u0448\u0435\u043A\u0443) \u0432\u043E\u0434\u043E\u0439, \u0446\u0432\u0435\u0442\u0430\u043C\u0438, \u0437\u0435\u0440\u043D\u0430\u043C\u0438 \u0438 \u043C\u0430\u0441\u043B\u043E\u043C .</p></div><div class="stanza"><a href="#s10.9" id="s10.9" class="num">10.9</a><p>\u0412\u0441\u0435 \u044D\u0442\u043E \u043E\u043D \u0434\u043E\u043B\u0436\u0435\u043D \u0432\u044B\u043B\u0438\u0442\u044C \u043D\u0430 \u0433\u043E\u043B\u043E\u0432\u0443 \u0443\u0447\u0435\u043D\u0438\u043A\u0443, \u043F\u0440\u0438\u043D\u044F\u0432 (\u043E\u0431\u0440\u0430\u0437) \u0414\u0430\u043A\u0448\u0438\u043D\u0430 \u043C\u0443\u0440\u0442\u0438. \u0412\u044B\u043F\u043E\u043B\u043D\u044F\u044F \u0430\u0431\u0445\u0438\u0448\u0435\u043A\u0443 \u0441 \u0430\u0441\u0442\u0440\u0430 \u043C\u0430\u043D\u0442\u0440\u043E\u0439 \u043E\u043D \u0434\u043E\u043B\u0436\u0435\u043D \u044F\u0432\u0438\u0442\u044C \u0420\u0443\u0434\u0440\u0430 \u0428\u0430\u043A\u0442\u0438 .</p></div><div class="stanza"><a href="#s10.10" id="s10.10" class="num">10.10</a><p>\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0438\u043C, \u043E\u0431\u044A\u0435\u0434\u0438\u043D\u0438\u0432\u0448\u0438\u0441\u044C \u0441 \u044D\u0442\u043E\u0439 (\u043C\u0430\u043D\u0442\u0440\u043E\u0439), \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0432\u0435\u0440\u0448\u0438\u0442\u044C \u0442\u0430\u0440\u043F\u0430\u043D\u0443 \u0442\u044B\u0441\u044F\u0447\u0443 \u0440\u0430\u0437. \u0422\u043E\u0433\u0434\u0430, \u043D\u0430\u0441\u0442\u043F\u0443\u043F\u0438\u0442 \u043D\u0430\u0447\u0430\u043B\u043E, \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u0435 \u0438 \u043E\u0431\u044A\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0435 \u0441 \u043D\u0435\u044E .</p></div><div class="stanza"><a href="#s10.11" id="s10.11" class="num">10.11</a><p>\u0411\u0435\u0437 \u0443\u0447\u0438\u0442\u0435\u043B\u044F , \u0430\u0431\u0445\u0438\u0448\u0435\u043A\u0438, (<em>\u0442\u0435\u043A\u0441\u0442 \u043F\u043E\u0432\u0440\u0435\u0436\u0434\u0435\u043D</em>) \u0431\u0435\u0437 \u043F\u0440\u0430\u0432\u0438\u043B\u0430 \u043C\u0430\u043D\u0442\u0440\u044B, \u043A\u0430\u043A \u043C\u043E\u0436\u043D\u043E (\u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0442\u044C) \u0430\u0434\u0445\u0438\u0432\u0430\u0441\u0443 (<em>\u0442\u0435\u043A\u0441\u0442 \u043F\u043E\u0432\u0440\u0435\u0436\u0434\u0435\u043D</em>) .</p></div><div class="stanza"><a href="#s10.12" id="s10.12" class="num">10.12</a><p>\u041E\u0431\u0440\u0435\u0442\u044F \u044D\u0442\u043E \u0442\u0440\u0443\u0434\u043D\u043E\u0434\u043E\u0441\u0442\u0438\u0436\u0438\u043C\u043E\u0435 \u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0435 \u043D\u0435 \u0434\u043E\u0441\u0442\u0438\u0436\u0438\u043C\u043E\u0435 \u0441\u0430\u043C\u043E\u0441\u0442\u043E\u044F\u0442\u0435\u043B\u044C\u043D\u043E, \u0441\u0430\u0434\u0445\u0430\u043A\u0430, \u0440\u0430\u0434\u0438 (\u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u044F) \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u0430 \u0432 \u043C\u0430\u043D\u0442\u0440\u0435 (\u043C\u0430\u043D\u0442\u0440\u0430 \u0441\u0438\u0434\u0434\u0445\u0438) \u0434\u043E\u043B\u0436\u0435\u043D \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u044C \u043E\u0431\u0435\u0442\u0443 \u043C\u0430\u043D\u0442\u0440\u044B .</p></div><div class="stanza"><a href="#s10.13" id="s10.13" class="num">10.13</a><p>\u0421\u043E\u0432\u0435\u0440\u0448\u0438\u0432 \u0442\u0430\u043A \u043D\u0430\u0437\u0432\u0430\u043D\u043D\u0443\u044E \u0430\u0431\u0445\u0438\u0448\u0435\u043A\u0443, \u0441\u043E\u0432\u0435\u0440\u0448\u0438\u0432 \u043E\u043C\u043E\u0432\u0435\u043D\u0438\u0435, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u0438\u0442\u044C \u0434\u0436\u0430\u043F\u0443 \u0446\u0430\u0440\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0432\u0438\u0434\u044C\u0438 (<em>\u043C\u0430\u043D\u0442\u0440\u044B</em>) \u0441\u0442\u043E \u0442\u044B\u0441\u044F\u0447 \u0440\u0430\u0437. \u0414\u0435\u0441\u044F\u0442\u0443\u044E \u0447\u0430\u0441\u0442\u044C \u043E\u0442 \u044D\u0442\u043E\u0433\u043E (\u0447\u0438\u0441\u043B\u0430) \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0432\u0435\u0440\u0448\u0438\u0442\u044C \u0442\u0430\u0440\u043F\u0430\u043D\u0443 .</p></div><div class="stanza"><a href="#s10.14" id="s10.14" class="num">10.14</a><p>\u0412\u044B\u043F\u043E\u043B\u043D\u0438\u0432, \u043A\u0430\u043A \u0440\u0430\u043D\u044C\u0448\u0435, \u0430\u0431\u0445\u0438\u0448\u0435\u043A\u0443, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u0438\u0442\u044C \u0434\u0436\u0430\u043F\u0443 \u043C\u0430\u043D\u0442\u0440\u0430 \u0448\u0438\u0440\u0430\u0441\u0430. \u0421\u0442\u0430\u0432 \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u044B\u043C \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0435\u043D\u043D\u044B\u043C \u0435\u044E, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 (\u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u0438\u0442\u044C \u0434\u0436\u0430\u043F\u0443) \u0434\u0432\u0430 \u043B\u0430\u043A\u0445\u0430 (200 000), \u043D\u0435\u0441\u043C\u044B\u043A\u0430\u044F \u0433\u043B\u0430\u0437 (\u0431\u0435\u0437 \u0441\u043D\u0430) .</p></div><div class="stanza"><a href="#s10.15" id="s10.15" class="num">10.15</a><p>\u0414\u0432\u0435 \u043B\u0430\u043A\u0448\u0438 (\u0438\u043C\u0435\u043D\u0443\u044E\u0442\u0441\u044F) \u0420\u0443\u0434\u0440\u0430\u043D\u0438, \u0447\u0435\u0442\u044B\u0440\u0435 - \u041F\u0443\u0440\u0443\u0448\u0442\u0443\u0442\u0430, \u043F\u044F\u0442\u044C \u043B\u0430\u043A\u0445\u043E\u0432, \u043E \u0414\u0435\u0432\u0438 (\u0438\u043C\u0435\u043D\u0443\u044E\u0442\u0441\u044F) \u041F\u0430\u0448\u0443\u043F\u0430\u0442\u0430 \u0438\u0445 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u0438\u0442\u044C;</p></div><div class="stanza"><a href="#s10.16" id="s10.16" class="num">10.16</a><p>\u041E\u0431\u043B\u0430\u0447\u0438\u0432\u0448\u0438\u0441\u044C \u0432 \u0431\u0435\u043B\u044B\u0435, \u043A\u0440\u0430\u0441\u043D\u044B\u0435, \u0436\u0435\u043B\u0442\u044B\u0435 \u0447\u0435\u0440\u043D\u044B\u0435 \u0438 \u043F\u0435\u0441\u0442\u0440\u044B\u0435 \u043E\u0434\u0435\u0436\u0434\u044B. \u0417\u0430\u0442\u0435\u043C \u0441\u0430\u0434\u0445\u0430\u043A\u0430 \u0437\u0430\u0449\u0438\u0449\u0435\u043D\u043D\u044B\u0439 \u043C\u0430\u043D\u0442\u0440\u0430\u043C\u0438 \u043F\u0440\u0438\u043C\u0435\u0442 \u043E\u0431\u0440\u0430\u0437 (\u043F\u043E\u0447\u0438\u0442\u0430\u0435\u043C\u043E\u0433\u043E \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0430) .</p></div><div class="stanza"><a href="#s10.17" id="s10.17" class="num">10.17</a><p>\u0411\u0435\u0437\u043C\u043E\u043B\u0432\u043D\u043E\u0435 \u043F\u0440\u043E\u0438\u0437\u043D\u0435\u0441\u0435\u043D\u0438\u0435 (\u0434\u0430\u0435\u0442 \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0435\u043D\u0438\u0435) \u0432\u0441\u0435\u0445 \u0433\u0440\u0435\u0445\u043E\u0432 \u0443\u0441\u0438\u043B\u0435\u043D\u0438\u0435 \u0441\u0438\u043B\u044B \u043C\u0430\u043D\u0442\u0440\u044B. \u041F\u0440\u0438\u043D\u044F\u0432 \u043E\u0431\u0435\u0442 \u0435\u0435 \u0432\u044B\u043F\u043E\u043D\u0435\u043D\u0438\u044F, \u0436\u0435\u043B\u0430\u044F \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u043E\u0432\u0430\u0442\u044C \u0435\u0435;</p></div><div class="stanza"><a href="#s10.18" id="s10.18" class="num">10.18</a><p>\u041F\u043E\u0434\u043D\u0435\u0441\u044F \u0430\u0440\u0433\u0445\u044C\u044E, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0431\u043B\u0430\u0433\u043E\u0433\u043E\u0432\u0435\u0439\u043D\u043E \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u0438\u0442\u044C \u0434\u0436\u0430\u043F\u0443 \u0434\u0435\u0432\u044F\u0442\u044C \u043B\u0430\u043A\u0445\u043E\u0432. \u041F\u043E\u0441\u043B\u0435 \u0445\u043E\u043C\u044B \u0441 \u0432\u044B\u0441\u0448\u0435\u0439 \u0434\u0440\u0430\u0432\u044C\u0435\u0439 (\u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0442\u044C) \u0442\u0430\u0440\u043F\u0430\u043D\u0443 \u0434\u0435\u0441\u044F\u0442\u043E\u0439 \u0447\u0430\u0441\u0442\u044C\u044E (\u043E\u0442 \u044D\u0442\u043E\u0433\u043E \u0447\u0438\u0441\u043B\u0430) .</p></div><div class="stanza"><a href="#s10.19" id="s10.19" class="num">10.19</a><p>(\u041F\u043E\u0434\u043D\u043E\u0441\u0438\u0442\u0441\u044F) \u043C\u044F\u0441\u043E, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0438\u043C\u0435\u043D\u0443\u044E\u0442 \u0412\u0435\u043B\u0438\u043A\u0438\u043C \u0432\u043B\u0430\u0434\u044B\u043A\u043E\u0439 \u0437\u0435\u043C\u043B\u0438, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0434\u0440\u0443\u0433\u0438\u0435 \u0432\u044B\u0441\u0448\u0438\u0435 \u0434\u0440\u0430\u0432\u044C\u0438, \u0432 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435 (\u043E\u0431\u0440\u044F\u0434\u0430), \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u044F \u044D\u0442\u043E \u0434\u0432\u0430 \u0440\u0430\u0437\u0430, \u0442\u0440\u0438 \u0440\u0430\u0437\u0430 \u0438 \u0438\u043B\u0438 \u043C\u0435\u043D\u044C\u0448\u0435 .</p></div><div class="stanza"><a href="#s10.20" id="s10.20" class="num">10.20</a><p>\u041C\u0430\u0441\u043B\u043E \u0433\u0443\u043D\u0433\u0443\u043B\u0430 (\u043D\u0430\u0434\u0435\u043B\u044F\u0435\u0442 ) \u0431\u043B\u0430\u0433\u043E\u0441\u043A\u043B\u043E\u043D\u043D\u043E\u0441\u0442\u044C\u044E (\u043B\u044E\u0431\u043E\u0432\u044C\u044E) \u0436\u0435\u043D\u0449\u0438\u043D, \u0440\u0430\u0432\u043D\u044B\u043C \u0435\u043C\u0443 \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044F \u0432\u0435\u043B\u0438\u043A\u043E\u0435 \u043C\u044F\u0441\u043E (<em>\u0447\u0435\u043B\u043E\u0432\u0435\u0447\u0438\u043D\u0430</em>). \u041C\u043E\u043B\u043E\u043A\u043E, \u0431\u0438\u043B\u044C\u0432\u0430, \u0441\u0435\u043C\u0435\u043D\u0430 \u043B\u043E\u0442\u043E\u0441\u0430 \u0438\u043C\u0435\u043D\u0443\u044E\u0442\u0441\u044F \u043D\u0435\u0441\u0440\u0430\u0432\u043D\u0435\u043D\u043D\u044B\u043C\u0438 \u043D\u0430 \u0437\u0435\u043C\u043B\u0435 .</p></div><div class="stanza"><a href="#s10.21" id="s10.21" class="num">10.21</a><p>\u0414\u0445\u0430\u0442\u0440\u0438 \u0438 \u0434\u0443\u0440\u0432\u0430 \u0440\u0430\u0432\u043D\u044B \u0430\u043C\u0440\u0438\u0442\u0435, \u0438\u043C \u0436\u0435 \u0440\u0430\u0432\u043D\u044B\u043C \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044F \u043C\u0430\u0441\u043B\u043E.</p><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0442\u044C \u0437\u0430\u0442\u0435\u043C (\u043E\u0431\u0440\u044F\u0434) \u0441 \u043C\u0430\u0441\u043B\u043E\u043C \u0438 \u043F\u0440\u043E\u0447\u0438\u043C, 9, 6, 3 \u0440\u0430\u0437 \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443 .</p></div><div class="stanza"><a href="#s10.22" id="s10.22" class="num">10.22</a><p>\u0412\u044B\u043F\u043E\u043B\u043D\u0438\u0432 \u044D\u0442\u043E \u043F\u0440\u0435\u0436\u0434\u0435, \u043F\u0443\u0441\u0442\u044C \u043C\u0443\u0434\u0440\u044B\u0439 \u0440\u0430\u0434\u0438 \u0443\u0441\u043F\u0435\u0445\u0430 (\u0441\u0438\u0434\u0434\u0445\u0438) \u043F\u043E\u0434\u043D\u0435\u0441\u0435\u0442 \u0430\u0440\u0433\u0445\u044C\u044E. \u041F\u043E\u0434\u043D\u0435\u0441\u044F \u0430\u0440\u0433\u0445\u044C\u044E, \u043F\u0443\u0441\u0442\u044C \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u0438\u0442 \u0434\u0436\u0430\u043F\u0443 (\u0432 \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u0438 \u043E\u0442 \u0442\u043E\u0433\u043E,) \u0441\u043A\u043E\u043B\u044C\u043A\u043E \u043E\u043D \u0436\u0435\u043B\u0430\u0435\u0442 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432 (\u0441\u0438\u0434\u0434\u0445\u0438) .</p></div><div class="stanza"><a href="#s10.23" id="s10.23" class="num">10.23</a><p>\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u0430\u044F \u043E\u0434\u043D\u043E\u043C\u0443 \u043B\u0430\u043A\u0445\u0443, \u0412\u043B\u0430\u0434\u044B\u043A\u0430 \u0437\u0435\u043C\u043B\u0438 \u043F\u0440\u0438\u043D\u043E\u0441\u0438\u0442 \u0441\u0438\u043B\u0443 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u044F. \u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0434\u0432\u0443\u043C (\u043B\u0430\u043A\u0445\u0430\u043C), \u043E \u0414\u0435\u0432\u0438 (\u0441\u0430\u0434\u0445\u0430\u043A\u0430) \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0432\u043B\u0430\u0434\u044B\u0447\u0435\u0441\u0442\u0432\u043E \u0438 \u043F\u0440\u0438\u0432\u043B\u0435\u0447\u0435\u043D\u0438\u0435 .</p></div><div class="stanza"><a href="#s10.24" id="s10.24" class="num">10.24</a><p>\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0442\u0440\u0435\u043C (\u043B\u0430\u043A\u0445\u0430\u043C) \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u0443\u043C\u0438\u0440\u043E\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435, \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0447\u0435\u0442\u044B\u0440\u0435\u043C - \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u0441\u0438\u043B\u0430. \u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043F\u044F\u0442\u0438 -\u0432\u0441\u044F \u043C\u0443\u0434\u0440\u043E\u0441\u0442\u044C, \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0448\u0435\u0441\u0442\u0438 -\u0441\u043E\u043D\u043C \u0433\u0430\u043D\u0434\u0445\u0430\u0440\u0432\u043E\u0432 .</p></div><div class="stanza"><a href="#s10.25" id="s10.25" class="num">10.25</a><p>\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0441\u0435\u043C\u0438 -\u0441\u0435\u043C\u044C \u043C\u0438\u0440\u043E\u0432, \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0434\u0435\u0441\u044F\u0442\u0438 \u043E\u043D \u0441\u0442\u0430\u043D\u0435\u0442 \u0440\u0430\u0432\u0435\u043D \u0438\u043C. \u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043F\u044F\u0442\u0438\u0434\u0435\u0441\u044F\u0442\u0438, \u043E\u043D \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 (\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F) \u0437\u0430 \u043D\u0435\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u044B\u043C, \u043E \u041C\u0430\u0445\u0435\u0448\u0432\u0430\u0440\u0438!</p></div><div class="stanza"><a href="#s10.26" id="s10.26" class="num">10.26</a><p>\u0417\u0430 \u041C\u0430\u0439\u0435\u0439, \u0441 \u0448\u0435\u0441\u0442\u044C\u044E \u043B\u0430\u043A\u0445\u0430\u043C\u0438, \u0437\u0430 \u0438\u0448\u0432\u0430\u0440\u043E\u0439 \u0441 \u0432\u043E\u0441\u044C\u043C\u0438\u0434\u0435\u0441\u044F\u0442\u044C\u044E, \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0434\u0435\u0441\u044F\u0442\u0438 \u043C\u0438\u043B\u043B\u0438\u043E\u043D\u0430\u043C \u0434\u0436\u0430\u043F \u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0433\u0440\u0430\u043D\u0438\u0446\u0443 \u0441\u0430\u043A\u0430\u043B\u044B .</p></div><div class="stanza"><a href="#s10.27" id="s10.27" class="num">10.27</a><p>\u0417\u0430\u0442\u0435\u043C \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0412\u0438\u0440\u044B, \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0432 \u0435\u0433\u043E. \u0412\u0441\u0435 (\u0432\u0441\u0435 \u0434\u0436\u0430\u043F\u044B) \u043A\u0430\u043A \u0431\u044B\u043B\u043E \u043E\u043F\u0438\u0441\u0430\u043D\u043E, \u0432 \u0442\u0435\u043C\u043D\u0443\u044E (\u043F\u043E\u043B\u043E\u0432\u0438\u043D\u0443 \u043C\u0435\u0441\u044F\u0446\u0430) \u0434\u043D\u0435\u043C \u0438\u043B\u0438 \u043D\u043E\u0447\u044C\u044E, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0442\u044C. (\u0422\u0430\u043A\u043E\u0432\u043E) \u044D\u0442\u043E \u043F\u0440\u0430\u0432\u0438\u043B\u043E .</p></div><div class="stanza"><a href="#s10.28" id="s10.28" class="num">10.28</a><p>\u0412\u044B\u043F\u043E\u043B\u043D\u0438\u0432 \u043E\u043F\u0438\u0441\u0430\u043D\u043D\u043E\u0435 \u0432\u044B\u0448\u0435 \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u0435, \u0441\u043E\u0432\u0435\u0440\u0448\u0438\u0432 \u043D\u0430\u0438\u043B\u0443\u0447\u0448\u0435\u0435 \u0432\u043E\u0437\u043B\u0438\u044F\u043D\u0438\u0435 \u0434\u0440\u0430\u0432\u044C\u0438, \u043F\u0443\u0441\u0442\u044C \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u044F\u0449\u0438\u0439 \u043C\u0430\u043D\u0442\u0440\u0443 \u0432\u044B\u043F\u0440\u044F\u043C\u0438\u0432 \u0442\u0443\u043B\u043E\u0432\u0438\u0449\u0435, \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u0438\u0442 \u0434\u0436\u0430\u043F\u0443, \u043D\u0435 \u043F\u043E\u0448\u0435\u0432\u0435\u043B\u0438\u0432\u0448\u0438\u0441\u044C, (\u0441\u0438\u0434\u044F) \u043B\u0438\u0446\u043E\u043C \u043D\u0430 \u0441\u0435\u0432\u0435\u0440;</p></div><div class="stanza"><a href="#s10.29" id="s10.29" class="num">10.29</a><p>\u0412\u044B\u043F\u043E\u043B\u043D\u044F\u044F (\u0435\u0435) \u0434\u043E \u0442\u0435\u0445 \u043F\u043E\u0440, \u043F\u043E\u043A\u0430 \u043D\u0435 (\u043F\u0440\u043E\u044F\u0432\u0438\u0442\u0441\u044F) \u0446\u0435\u043B\u0438\u043A\u043E\u043C \u043C\u043E\u0433\u0443\u0449\u0435\u0441\u0442\u0432\u043E \u0439\u043E\u0433\u0438. (\u041A\u043E\u0433\u0434\u0430 \u043E\u043D) \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0442 (\u0435\u0435), (\u044F\u0432\u0438\u0442\u0441\u044F) \u0431\u0435\u0441\u043F\u043E\u0440\u044F\u0434\u043E\u0447\u043D\u044B\u0439 \u0448\u0443\u043C, \u0443\u0436\u0430\u0441\u043D\u044B\u0439 \u0438 \u0447\u0440\u0435\u0437\u0432\u044B\u0447\u0430\u0439\u043D\u043E \u0441\u0438\u043B\u044C\u043D\u044B\u0439 .</p></div><div class="stanza"><a href="#s10.30" id="s10.30" class="num">10.30</a><p>(\u041A\u0442\u043E) \u0443\u043F\u0430\u0432 \u043D\u0430 \u0437\u0435\u043C\u043B\u044E \u0441\u043C\u043E\u0436\u0435\u0442 \u043F\u043E\u0434\u043D\u044F\u0442\u044C\u0441\u044F \u0438 \u0443\u0441\u0442\u043E\u044F\u0442\u044C- \u0442\u043E\u0442 \u0412\u043B\u0430\u0434\u044B\u043A\u0430 \u0441\u0430\u0434\u0445\u0430\u043A\u043E\u0432. \u0412\u044B\u043F\u043E\u043B\u043D\u0438\u0432 \u0434\u043B\u044F \u043D\u0438\u0445 \u043F\u043E\u043A\u043B\u043E\u043D, \u043E\u0442\u0434\u0435\u043B\u0438\u0432 \u043B\u0435\u0432\u0443\u044E \u0447\u0430\u0441\u0442\u044C \u0442\u0435\u043B\u0430 .</p></div><div class="stanza"><a href="#s10.31" id="s10.31" class="num">10.31</a><p>\u0418 \u043F\u043E\u0434\u043D\u044F\u0432\u0448\u0438\u0441\u044C \u043A \u043D\u0438\u043C, \u043F\u043E\u0434\u043D\u0435\u0441\u044F \u0430\u0440\u0433\u044C\u0445\u044E, \u0441\u0442\u0430\u043D\u0435\u0442 \u0440\u0430\u0432\u043D\u044B\u043C \u0438\u043C. \u0414\u0430\u0436\u0435 \u043D\u0430\u0441\u0442\u0430\u0432\u043D\u0438\u043A \u0434\u043E\u043B\u0436\u0435\u043D \u0432\u044B\u043F\u043E\u044F\u043D\u0442\u044C (\u0434\u0436\u0430\u043F\u0443) \u043A\u0430\u0436\u0434\u044B\u0439 \u0434\u0435\u043D\u044C \u0441\u043E\u0445\u0440\u0430\u043D\u044F\u044F \u043C\u043E\u043B\u0447\u0430\u043D\u0438\u0435 \u0432 \u0442\u0435\u0447\u0435\u043D\u0438\u0438 \u0448\u0435\u0441\u0442\u0438 \u043C\u0435\u0441\u044F\u0446\u0435\u0432;</p></div><div class="stanza"><a href="#s10.32" id="s10.32" class="num">10.32</a><p>(\u041F\u0440\u0430\u043A\u0442\u0438\u043A\u0443\u044F) \u0434\u0435\u0441\u044F\u0442\u044C \u0438 \u043F\u044F\u0442\u044C \u043C\u0430\u043D\u0442\u0440, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0431\u044B\u043B\u0438 \u0440\u0430\u043D\u044C\u0448\u0435 \u043D\u0430\u0437\u0432\u0430\u043D\u044B \u043C\u043D\u043E\u0439 \u0422\u0435\u0431\u0435; \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u0439 \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0435\u0439 \u041D\u044C\u044F\u0441\u043E\u0439, \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u044F \u0442\u0440\u0438\u0436\u0434\u044B (\u0432 \u0434\u0435\u043D\u044C)\u043E\u0433\u043D\u0435\u043D\u043D\u044B\u0439 \u0440\u0438\u0442\u0443\u0430\u043B .</p></div><div class="stanza"><a href="#s10.33" id="s10.33" class="num">10.33</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u043E\u043F\u0438\u0441\u0430\u043D\u043D\u044B\u0439 \u0432\u044B\u0448\u0435 \u0442\u0440\u0435\u0437\u0443\u0431\u0435\u0446, \u0441\u043E\u0431\u043B\u044E\u0434\u0430\u044F \u0431\u0440\u0430\u0445\u043C\u0430\u0447\u0430\u0440\u044C\u044E, \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0432 \u043E\u043F\u0438\u0441\u0430\u043D\u043D\u043E\u0435 \u0432\u044B\u0448\u0435 \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u0435 \u0432 \u043E\u043A\u0440\u0443\u0436\u0435\u043D\u0438\u0438 \u0442\u0440\u0435\u0445 \u0428\u0430\u043A\u0442\u0438 .</p></div><div class="stanza"><a href="#s10.34" id="s10.34" class="num">10.34</a><p>\u041F\u0443\u0441\u0442\u044C \u0443\u0447\u0438\u0442\u0435\u043B\u044C \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0442 \u0430\u0431\u0445\u0438\u0448\u0435\u043A\u0443 \u043D\u0430\u0434 \u043D\u0438\u043C \u0438 \u043D\u0430\u0434 \u0441\u043E\u0431\u043E\u0439 \u0432 \u043D\u0430\u0447\u0430\u043B\u0435 \u0438 \u0432 \u043A\u043E\u043D\u0446\u0435. \u0421\u0442\u0430\u0432 \u043F\u0440\u0438\u043D\u044F\u0432\u0448\u0438\u043C \u043E\u0431\u0435\u0442, \u043E\u043D \u0441\u0442\u0430\u043D\u0435\u0442 \u043B\u0443\u0447\u0448\u0438\u043C \u0441\u0440\u0435\u0434\u0438 \u0437\u043D\u0430\u044E\u0449\u0438\u0445 \u043C\u0430\u043D\u0442\u0440\u0443 .</p></div><div class="stanza"><a href="#s10.34" id="s10.34" class="num">10.34</a><p>\u0412\u044B\u043F\u043E\u043B\u043D\u044F\u044E\u0449\u0438\u0439 \u043E\u0431\u0440\u044F\u0434\u044B \u0431\u043B\u0430\u0433\u043E\u0441\u043B\u043E\u0432\u0435\u043D\u0438\u044F \u0438 \u043F\u0440\u043E\u043A\u043B\u044F\u0442\u0438\u044F, \u043E\u043D \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0443\u044F\u0437\u0432\u0438\u043C. \u0414\u043B\u044F \u0435\u0433\u043E \u043E\u0447\u0438\u0449\u0435\u043D\u0438\u044F \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043C\u0435\u0441\u0442\u0438\u0442\u044C \u043C\u0443\u043B\u0430 \u043C\u0430\u043D\u0442\u0440\u0443, \u0442\u0440\u0438 \u0440\u0430\u0437\u0430 \u043F\u043E \u0442\u0440\u0438 .</p></div><div class="stanza"><a href="#s10.36" id="s10.36" class="num">10.36</a><p>\u0412 \u043B\u0435\u0432\u043E\u043C \u0431\u043E\u043B\u044C\u0448\u043E\u043C \u043F\u0430\u043B\u044C\u0446\u0435, \u043B\u0430\u0434\u043E\u043D\u0438, \u0433\u043B\u0430\u0437\u0430\u0445, \u0443\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0445 \u043F\u0430\u043B\u044C\u0446\u0430\u0445, \u0432 \u0430\u0441\u0442\u0440\u0435, \u0441 \u043C\u0435\u0447\u0451\u043C \u0410, \u041A\u0428\u0410 \u0425\u0420\u0418\u041C, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0440\u0430\u0437\u043C\u0435\u0441\u0442\u0438\u0442\u044C \u0448\u0430\u0431\u0434\u0430\u0440\u0430\u0448\u0438 (\u0430\u043B\u0444\u0430\u0432\u0438\u0442) .</p></div><div class="stanza"><a href="#s10.37" id="s10.37" class="num">10.37</a><p>(\u0421 \u043C\u0430\u043D\u0442\u0440\u0430\u043C\u0438) \u041D\u0410, \u041F\u0425\u0410, \u0425\u0420\u0418\u041C (\u0440\u0430\u0437\u043C\u0435\u0449\u0430\u044E\u0442\u0441\u044F) \u0441\u0442\u0430\u0440\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u043E\u0431\u0440\u0430\u0437 \u0428\u0430\u043A\u0442\u0438. \u041E\u0431\u0440\u0430\u0442\u043D\u0430\u044F, \u043C\u0430\u0445\u0430\u043C\u0443\u0434\u0440\u0430, \u043F\u0440\u0430\u0439\u043E\u0433\u0430 \u0438 \u043C\u0443\u043B\u0430 (\u043C\u0430\u043D\u0442\u0440\u0430);</p><p>\u0412 \u0441\u0432\u043E\u0438\u0445 \u043C\u0435\u0441\u0442\u0430\u0445 \u0442\u0435\u043B\u0430. \u042D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0441\u0430\u043C\u0430\u043D\u044C\u044F \u043D\u044C\u044F\u0441\u043E\u0439.</p></div><p>\u0422\u0430\u043A\u043E\u0432\u0430 \u0432 \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0439 \xAB\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0435\xBB \u0434\u0435\u0441\u044F\u0442\u0430\u044F \u0433\u043B\u0430\u0432\u0430.</p>',38),p=[n];function l(v,e,t,r,m,f){return i(),a("div",null,p)}var z=s(c,[["render",l]]);export{h as __pageData,z as default};
